"""Regression tests for the SLURM wrapper script generated by
:meth:`SlurmJobManager.generate_wrapper_script`.

The wrapper renderer (a18a3966) emits an ``exec <bin> <args>`` stub —
there is no longer an inline bash body. The tests guard the stub contract:

1. **Stub shape** — exactly a ``#!/usr/bin/env bash`` shebang + a single
   ``exec <wrapper_bin_path> <args>`` line. Both connection modes produce
   the same two-line shape; the binary parses the args and runs the full
   secondary lifecycle.

2. **Exec target** — the ``exec`` line invokes the path supplied via
   ``wrapper_bin_path``; this is the anti-drift guard for the Python-layer
   plumbing that threads the uploaded binary path through the call chain.

3. **``extra_run_args`` encoding** — each entry of
   ``TaskDeploymentSpec.extra_run_args`` must appear as an
   ``--extra-run-arg <value>`` entry in the exec args and must be present
   in BOTH connection modes. Default ``()`` produces no ``--extra-run-arg``
   entries.

The image-validation test wrapper (``generate_test_wrapper_script``) is a
separate inline-bash script that still traps ``EXIT TERM HUP INT``
(commit 485629c) and is validated by
:func:`test_test_wrapper_traps_termination_signals`.
"""

from __future__ import annotations

from pathlib import Path

import pytest

from dynamic_runner.deployment_spec import TaskDeploymentSpec
from dynamic_runner.packaging.job_manager import SlurmJobManager
from dynamic_runner.packaging.podman import PodmanImageMetadata, PodmanPackaging
from dynamic_runner.packaging.slurm_config import SlurmConfig


def _exec_line(wrapper: str) -> str:
    """Extract the ``exec …`` line from a two-line wrapper stub.

    Raises ``AssertionError`` if the wrapper does not have exactly the
    expected shebang + exec-line shape (two non-empty lines after
    stripping trailing whitespace)."""
    lines = [ln for ln in wrapper.splitlines() if ln.strip()]
    assert len(lines) == 2, (
        "wrapper stub must be exactly shebang + exec line; "
        f"got {len(lines)} non-empty lines:\n{wrapper!r}"
    )
    assert lines[0] == "#!/usr/bin/env bash", (
        f"first line must be the shebang; got: {lines[0]!r}"
    )
    assert lines[1].startswith("exec "), (
        f"second line must be an exec invocation; got: {lines[1]!r}"
    )
    return lines[1]


def _extra_run_args_from_exec(exec_line: str) -> list[str]:
    """Return the values of every ``--extra-run-arg <value>`` pair
    in the exec-line tokens.

    The renderer shell-quotes each argument, but the simple ``--extra-run-arg``
    flag token is always bare (no quoting needed). We extract only these
    entries — the presence/order of other flags is validated separately."""
    # Split on whitespace but respect single-quoted segments (the renderer
    # uses single-quoting for the load-command argument).
    tokens: list[str] = []
    current = ""
    in_quote = False
    for ch in exec_line:
        if ch == "'" and not in_quote:
            in_quote = True
            continue
        if ch == "'" and in_quote:
            in_quote = False
            continue
        if ch == " " and not in_quote:
            if current:
                tokens.append(current)
                current = ""
        else:
            current += ch
    if current:
        tokens.append(current)

    values: list[str] = []
    i = 0
    while i < len(tokens):
        if tokens[i] == "--extra-run-arg" and i + 1 < len(tokens):
            values.append(tokens[i + 1])
            i += 2
        else:
            i += 1
    return values


_TEST_DEPLOYMENT = TaskDeploymentSpec(
    secondary_module="test_pkg",
    image_name="test-image",
)

# Dummy gateway-side path for the wrapper binary. The renderer requires
# this (legacy inline-bash body was removed in a18a3966); tests don't need
# an actual file — any absolute path satisfies the string kwarg.
_STUB_WRAPPER_BIN_PATH = "/gw/dynrunner-slurm-wrapper"


class _StubGateway:
    """Minimal gateway stub. ``generate_wrapper_script`` only ever
    consults ``remote_home`` (via ``_expand_path``) and never calls
    ``execute_command`` / ``transfer_file`` itself, so a no-op is
    sufficient."""

    remote_home = "/home/test"
    host = "gateway.example"


@pytest.fixture
def manager(tmp_path: Path) -> SlurmJobManager:
    slurm_config = SlurmConfig(root_folder=str(tmp_path / "slurm-root"))
    packaging = PodmanPackaging(deployment=_TEST_DEPLOYMENT)
    return SlurmJobManager(
        gateway=_StubGateway(),
        slurm_config=slurm_config,
        packaging_method=packaging,
        deployment=_TEST_DEPLOYMENT,
    )


@pytest.fixture
def image_metadata(tmp_path: Path) -> PodmanImageMetadata:
    return PodmanImageMetadata(
        remote_path=tmp_path / "image.tar",
        image_hash="0" * 64,
        uploaded=False,
    )


@pytest.mark.parametrize("reverse_connection", [False, True])
def test_wrapper_stub_shape(
    manager: SlurmJobManager,
    image_metadata: PodmanImageMetadata,
    reverse_connection: bool,
) -> None:
    """The rendered wrapper is exactly shebang + ``exec <bin> <args>``.

    The legacy inline-bash body was removed in a18a3966; the binary stub
    is the ONLY render path. Both connection modes produce the same
    two-line shape — the binary parses the args and runs the full
    secondary lifecycle. This guards against any future renderer change
    that re-introduces an inline body."""
    wrapper = manager.generate_wrapper_script(
        image_metadata=image_metadata,
        secondary_id="secondary-0",
        gateway_host="gateway.example",
        gateway_port=12345,
        reverse_connection=reverse_connection,
        wrapper_bin_path=_STUB_WRAPPER_BIN_PATH,
    )

    # _exec_line asserts the two-line shape internally.
    _exec_line(wrapper)


@pytest.mark.parametrize("reverse_connection", [False, True])
def test_wrapper_exec_invokes_supplied_binary(
    manager: SlurmJobManager,
    image_metadata: PodmanImageMetadata,
    reverse_connection: bool,
) -> None:
    """The ``exec`` line must invoke exactly the path supplied via
    ``wrapper_bin_path``. This is the Python-layer plumbing guard: the
    preparation step uploads the binary and threads the gateway-side path
    through to ``generate_wrapper_script``; the stub must carry that exact
    path so the SLURM job finds the right binary."""
    wrapper = manager.generate_wrapper_script(
        image_metadata=image_metadata,
        secondary_id="secondary-0",
        gateway_host="gateway.example",
        gateway_port=12345,
        reverse_connection=reverse_connection,
        wrapper_bin_path=_STUB_WRAPPER_BIN_PATH,
    )

    line = _exec_line(wrapper)
    assert line.startswith(f"exec {_STUB_WRAPPER_BIN_PATH} "), (
        f"exec line must invoke {_STUB_WRAPPER_BIN_PATH!r}; got:\n{line}"
    )


def test_test_wrapper_traps_termination_signals(
    manager: SlurmJobManager,
    image_metadata: PodmanImageMetadata,
) -> None:
    """The image-validation test wrapper must also use the
    full-signal trap. It's used by ``slurm-validate-image`` from a
    sibling code path, and the same /tmp-leak class applies."""
    wrapper = manager.generate_test_wrapper_script(image_metadata=image_metadata)

    assert "trap cleanup EXIT TERM HUP INT" in wrapper, (
        "test wrapper trap must include TERM/HUP/INT in addition to EXIT"
    )


def _build_manager(
    tmp_path: Path,
    extra_run_args: tuple[str, ...],
) -> SlurmJobManager:
    """Build a :class:`SlurmJobManager` whose deployment carries the
    requested ``extra_run_args``. Mirrors the ``manager`` fixture but
    parametrises the deployment field — kept separate so the existing
    fixture-based tests remain unchanged."""
    deployment = TaskDeploymentSpec(
        secondary_module="test_pkg",
        image_name="test-image",
        extra_run_args=extra_run_args,
    )
    slurm_config = SlurmConfig(root_folder=str(tmp_path / "slurm-root"))
    packaging = PodmanPackaging(deployment=deployment)
    return SlurmJobManager(
        gateway=_StubGateway(),
        slurm_config=slurm_config,
        packaging_method=packaging,
        deployment=deployment,
    )


@pytest.mark.parametrize("reverse_connection", [False, True])
def test_wrapper_omits_extra_run_args_when_default(
    tmp_path: Path,
    image_metadata: PodmanImageMetadata,
    reverse_connection: bool,
) -> None:
    """With the default ``extra_run_args=()`` the exec stub must carry
    no ``--extra-run-arg`` entries at all. Consumer-only flags such as
    ``--cap-add``, ``--shm-size``, and non-nproc ``--ulimit=`` values
    must be absent; the framework's own pids-limit and nproc-ulimit
    defaults are applied internally by the wrapper binary (not encoded
    in the stub args)."""
    manager = _build_manager(tmp_path, extra_run_args=())
    wrapper = manager.generate_wrapper_script(
        image_metadata=image_metadata,
        secondary_id="secondary-0",
        gateway_host="gateway.example",
        gateway_port=12345,
        reverse_connection=reverse_connection,
        wrapper_bin_path=_STUB_WRAPPER_BIN_PATH,
    )

    extra_args = _extra_run_args_from_exec(_exec_line(wrapper))
    assert extra_args == [], (
        f"default extra_run_args=() must produce no --extra-run-arg entries; "
        f"got: {extra_args!r}"
    )


@pytest.mark.parametrize("reverse_connection", [False, True])
def test_wrapper_consumer_pids_limit_appears_in_exec_args(
    tmp_path: Path,
    image_metadata: PodmanImageMetadata,
    reverse_connection: bool,
) -> None:
    """A consumer-supplied ``--pids-limit=N`` must appear as an
    ``--extra-run-arg --pids-limit=N`` entry in the exec stub so the
    wrapper binary receives it and passes it to ``podman run``. The
    binary applies its own framework default first and the consumer's
    value last, so podman's last-wins parsing selects the consumer's
    value — that ordering is the binary's responsibility, tested in the
    Rust binary_stub round-trip tests."""
    consumer_value = "--pids-limit=65536"
    manager = _build_manager(tmp_path, extra_run_args=(consumer_value,))
    wrapper = manager.generate_wrapper_script(
        image_metadata=image_metadata,
        secondary_id="secondary-0",
        gateway_host="gateway.example",
        gateway_port=12345,
        reverse_connection=reverse_connection,
        wrapper_bin_path=_STUB_WRAPPER_BIN_PATH,
    )

    extra_args = _extra_run_args_from_exec(_exec_line(wrapper))
    assert consumer_value in extra_args, (
        f"consumer-supplied {consumer_value!r} must appear as an "
        f"--extra-run-arg entry; got: {extra_args!r}"
    )


@pytest.mark.parametrize("reverse_connection", [False, True])
def test_wrapper_consumer_nproc_ulimit_appears_in_exec_args(
    tmp_path: Path,
    image_metadata: PodmanImageMetadata,
    reverse_connection: bool,
) -> None:
    """A consumer-supplied ``--ulimit=nproc=N:N`` must appear as an
    ``--extra-run-arg --ulimit=nproc=N:N`` entry in the exec stub.
    Mirrors :func:`test_wrapper_consumer_pids_limit_appears_in_exec_args`
    for the nproc ulimit override path."""
    consumer_value = "--ulimit=nproc=65536:65536"
    manager = _build_manager(tmp_path, extra_run_args=(consumer_value,))
    wrapper = manager.generate_wrapper_script(
        image_metadata=image_metadata,
        secondary_id="secondary-0",
        gateway_host="gateway.example",
        gateway_port=12345,
        reverse_connection=reverse_connection,
        wrapper_bin_path=_STUB_WRAPPER_BIN_PATH,
    )

    extra_args = _extra_run_args_from_exec(_exec_line(wrapper))
    assert consumer_value in extra_args, (
        f"consumer-supplied {consumer_value!r} must appear as an "
        f"--extra-run-arg entry; got: {extra_args!r}"
    )


@pytest.mark.parametrize("reverse_connection", [False, True])
def test_wrapper_injects_extra_run_args_in_exec_stub(
    tmp_path: Path,
    image_metadata: PodmanImageMetadata,
    reverse_connection: bool,
) -> None:
    """Each entry of ``TaskDeploymentSpec.extra_run_args`` must appear
    as an ``--extra-run-arg <value>`` pair in the exec stub, in the
    supplied order, and in BOTH connection modes. The wrapper binary
    splices these entries into the ``podman run`` invocation before the
    image-tag argument.

    Uses ``--ulimit=nofile=65536`` and ``--shm-size=2g`` as canonical
    consumer-only flags (``--pids-limit`` is now a framework default
    applied by the binary; its override path is exercised by
    :func:`test_wrapper_consumer_pids_limit_appears_in_exec_args`)."""
    extra = ("--ulimit=nofile=65536", "--shm-size=2g")
    manager = _build_manager(tmp_path, extra_run_args=extra)
    wrapper = manager.generate_wrapper_script(
        image_metadata=image_metadata,
        secondary_id="secondary-0",
        gateway_host="gateway.example",
        gateway_port=12345,
        reverse_connection=reverse_connection,
        wrapper_bin_path=_STUB_WRAPPER_BIN_PATH,
    )

    extra_args = _extra_run_args_from_exec(_exec_line(wrapper))
    for flag in extra:
        assert flag in extra_args, (
            f"extra_run_args entry {flag!r} must appear as an "
            f"--extra-run-arg value in the exec stub; got: {extra_args!r}"
        )
    # Order must be preserved: the binary passes them in-order to podman.
    for i, flag in enumerate(extra):
        for later_flag in extra[i + 1 :]:
            assert extra_args.index(flag) < extra_args.index(later_flag), (
                f"extra_run_args order must be preserved: {flag!r} must "
                f"precede {later_flag!r}; got order: {extra_args!r}"
            )
